const o=".floating-toolbar{height:100%;display:flex;flex-direction:row;justify-content:center;align-items:center;gap:3px;padding:2px 7px;box-sizing:border-box;border-radius:7px;color:var(--theme-gray-600);background-color:var(--theme-white-secondary);box-shadow:0 0 1px #0003,0 0 3px #0003,0 0 10px #00000012}:host{position:absolute;z-index:1;display:flex}button{all:unset}.icon{cursor:pointer;padding:3px;border-radius:5px}.icon:hover{background-color:var(--theme-gray-200)}.icon:active{background-color:var(--theme-theme-gray-100)}.icon[is-hidden]{display:none}.svg-icon{display:inline-flex;justify-content:center;align-items:center;width:.9em;height:.9em;color:currentColor;transition:transform 80ms linear;transform-origin:center}.svg-icon svg{fill:currentColor;width:100%;height:100%}.popper-tooltip{position:absolute;width:max-content;left:0;top:0;z-index:1;background:var(--gray-800);color:#fff;box-shadow:0 0 1px #0009,0 0 3px #0000000d;padding:0 5px 1px;border-radius:4px;font-size:var(--font-d3);line-height:.9;display:flex;justify-content:center;box-sizing:border-box;opacity:1;transform:scale(1);transform-origin:right center;transition:opacity .15s linear,transform .15s linear}.popper-tooltip.no-transition{transition:none}.popper-tooltip[placement=right]{transform-origin:left center}.popper-tooltip[placement=bottom]{transform-origin:top center}.popper-tooltip[placement=top]{transform-origin:bottom center}.popper-tooltip.hidden{opacity:0;pointer-events:none;transform:scale(.8)}.popper-tooltip.no-show{display:none}.popper-tooltip .popper-content{max-width:300px;max-height:200px;line-height:1.2;padding:2px 0;box-sizing:border-box;display:flex;flex-flow:column}.popper-tooltip .popper-arrow{position:absolute;background:var(--gray-800);width:8px;height:8px;transform:rotate(45deg);opacity:1}.popper-tooltip .popper-arrow.hidden{opacity:0}";export{o as c};